import Foundation
import Security

/// On-disk store for the HTTP control bearer token (D9, Errata E20).
///
/// The token file lives at ``fileURL`` with mode `0600`. The token
/// itself is 32 random bytes generated by `SecRandomCopyBytes`,
/// base64-encoded for safe transport in `Authorization: Bearer`
/// headers.
///
/// Per D9 the token is **never** injected into spawned PTY child
/// environments; only the HTTP listener reads this file. The store
/// itself never touches AppKit / `UserDefaults` so it is unit
/// testable from the `CmuxTerminalAccess` swift test target. The
/// app-target ``HTTPControlSettings`` composes this type plus the
/// `UserDefaults`-backed knobs.
///
/// Example:
/// ```swift
/// let store = HTTPControlTokenStore(
///     fileURL: supportDir.appendingPathComponent("http-control-token")
/// )
/// let bearer = try store.ensureToken()
/// ```
public final class HTTPControlTokenStore: @unchecked Sendable {
    /// On-disk location of the token file. Callers typically pass
    /// `<supportDirectory>/http-control-token`.
    public let fileURL: URL

    /// Creates a store bound to a fixed file path. The file is
    /// created lazily on the first ``ensureToken()`` call.
    public init(fileURL: URL) {
        self.fileURL = fileURL
    }

    /// Returns the existing token, or generates one (and creates the
    /// file with mode `0600`) if absent. If the file exists with a
    /// looser mode, this re-applies `0600` before reading.
    ///
    /// - Throws: When the token file cannot be read or its
    ///   permissions cannot be enforced.
    public func ensureToken() throws -> String {
        if FileManager.default.fileExists(atPath: fileURL.path) {
            try FileManager.default.setAttributes(
                [.posixPermissions: 0o600],
                ofItemAtPath: fileURL.path
            )
            return try String(contentsOf: fileURL, encoding: .utf8)
        }
        return try rotateToken()
    }

    /// Generates a fresh token via `SecRandomCopyBytes`, atomically
    /// overwrites the file, and re-applies mode `0600`. Phase 1's
    /// settings UI invokes this; Phase 1 lifecycle wires the rotation
    /// to invalidate active connections.
    ///
    /// - Throws: When the random source fails or the file cannot be
    ///   written.
    @discardableResult
    public func rotateToken() throws -> String {
        var bytes = Data(count: 32)
        let status = bytes.withUnsafeMutableBytes { ptr -> Int32 in
            guard let base = ptr.baseAddress else { return errSecParam }
            return SecRandomCopyBytes(kSecRandomDefault, 32, base)
        }
        guard status == errSecSuccess else {
            throw NSError(
                domain: "HTTPControlTokenStore",
                code: Int(status),
                userInfo: [NSLocalizedDescriptionKey: "SecRandomCopyBytes failed"]
            )
        }
        let token = bytes.base64EncodedString()
        let dir = fileURL.deletingLastPathComponent()
        try FileManager.default.createDirectory(
            at: dir,
            withIntermediateDirectories: true,
            attributes: [.posixPermissions: 0o700]
        )
        let tmp = dir.appendingPathComponent(
            "http-control-token.tmp.\(UUID().uuidString)"
        )
        try Data(token.utf8).write(to: tmp, options: .atomic)
        try FileManager.default.setAttributes(
            [.posixPermissions: 0o600],
            ofItemAtPath: tmp.path
        )
        if FileManager.default.fileExists(atPath: fileURL.path) {
            _ = try FileManager.default.replaceItemAt(fileURL, withItemAt: tmp)
        } else {
            try FileManager.default.moveItem(at: tmp, to: fileURL)
        }
        try FileManager.default.setAttributes(
            [.posixPermissions: 0o600],
            ofItemAtPath: fileURL.path
        )
        return token
    }
}
